query:
-- حذف جميع الربطات القديمة
DELETE FROM role_permissions;

-- 1. الحارس (المستوى 1) - تسجيل الحضور فقط
INSERT INTO role_permissions (role_id, permission_id) 
SELECT 1, id FROM permissions WHERE code IN ('view_attendance', 'edit_attendance');

-- 2. المشرف (المستوى 2) - إدارة العمال والمجموعات والحضور
INSERT INTO role_permissions (role_id, permission_id)
SELECT 2, id FROM permissions WHERE code IN (
  'view_workers', 'create_workers', 'edit_workers',
  'view_groups', 'create_groups', 'edit_groups',
  'view_attendance', 'edit_attendance', 'view_reports'
);

-- 3. المحاسب المالي والمراجع (المستوى 3) - التقارير المالية والرواتب
INSERT INTO role_permissions (role_id, permission_id)
SELECT 3, id FROM permissions WHERE code IN (
  'view_payroll', 'view_reports', 'export_data',
  'view_cost_centers'
);

-- 4. الشؤون الإدارية (المستوى 4) - المستخدمين ومراكز التكلفة
INSERT INTO role_permissions (role_id, permission_id)
SELECT 4, id FROM permissions WHERE code IN (
  'view_users', 'create_users', 'edit_users',
  'view_cost_centers', 'create_cost_centers', 'edit_cost_centers',
  'view_workers', 'view_groups', 'view_attendance', 'view_reports'
);

-- 5. المدير المالي (المستوى 5) - الموافقة على الرواتب والتقارير
INSERT INTO role_permissions (role_id, permission_id)
SELECT 5, id FROM permissions WHERE code IN (
  'view_payroll', 'approve_payroll', 'view_reports', 'export_data',
  'view_cost_centers', 'create_cost_centers', 'edit_cost_centers',
  'view_workers', 'view_groups', 'view_attendance'
);

-- 6. المدير العام (المستوى 6) - جميع الصلاحيات
INSERT INTO role_permissions (role_id, permission_id)
SELECT 6, id FROM permissions;

